function scoreColor(s: number) {
  return s >= 8.5 ? "#12B76A" : s >= 7 ? "#0000FF" : s >= 5.5 ? "#DFB300" : "#E82222"
}
function badgeClass(l: string) {
  return l === "ممتاز" ? "kb-badge-exc" : l === "جيد جداً" ? "kb-badge-good" : l === "جيد" ? "kb-badge-fair" : "kb-badge-weak"
}

function arabicGrammarCheck(text: string) {
  const rules: any[] = [
    {w:"اذا",c:"إذا",t:"همزة قطع"},{w:"الى",c:"إلى",t:"همزة قطع"},{w:"انا",c:"أنا",t:"همزة قطع"},
    {w:"انت",c:"أنت",t:"همزة قطع"},{w:"او",c:"أو",t:"همزة قطع"},{w:"اي",c:"أي",t:"همزة قطع"},
    {w:"اول",c:"أول",t:"همزة قطع"},{w:"اكثر",c:"أكثر",t:"همزة قطع"},{w:"انه",c:"أنه",t:"همزة قطع"},
    {w:"انها",c:"أنها",t:"همزة قطع"},{w:"احد",c:"أحد",t:"همزة قطع"},{w:"افضل",c:"أفضل",t:"همزة قطع"},
    {w:"اهم",c:"أهم",t:"همزة قطع"},{w:"اكبر",c:"أكبر",t:"همزة قطع"},
    {w:"كتابه",c:"كتابة",t:"تاء مربوطة"},{w:"دراسه",c:"دراسة",t:"تاء مربوطة"},
    {w:"حياه",c:"حياة",t:"تاء مربوطة"},{w:"سنه",c:"سنة",t:"تاء مربوطة"},
    {w:"فكره",c:"فكرة",t:"تاء مربوطة"},{w:"لحظه",c:"لحظة",t:"تاء مربوطة"},
    {w:"قصه",c:"قصة",t:"تاء مربوطة"},{w:"مشكله",c:"مشكلة",t:"تاء مربوطة"},
    {phrase:true,w:"انشاء الله",c:"إن شاء الله",t:"همزة قطع"},
    {phrase:true,w:"ان شاء الله",c:"إن شاء الله",t:"همزة قطع"},
  ]
  const results: any[] = [], seen = new Set<string>()
  const sents = text.split(/[.!?؟\n]+/).map(s=>s.trim()).filter(Boolean)
  rules.forEach(r => {
    if (r.phrase) {
      if (text.includes(r.w) && !seen.has(r.w)) { seen.add(r.w); results.push({wrong:r.w,correct:r.c,type:r.t,sentence:sents.find(s=>s.includes(r.w))||""}) }
    } else {
      text.split(/\s+/).forEach((w,i) => {
        const cl = w.replace(/[،.!؟:;"'«»\[\]()]/g,"")
        if (cl===r.w && !seen.has(r.w+"|"+i)) { seen.add(r.w+"|"+i); results.push({wrong:r.w,correct:r.c,type:r.t,sentence:sents.find(s=>s.includes(w)||"")}) }
      })
    }
  })
  return results
}

async function callAPI(text: string, prompt: string) {
  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1/models/${MODEL}:generateContent?key=${GOOGLE_API_KEY}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [
          { role: "user", parts: [{ text: `${prompt}\n\n---\n\nالنص المراد تحليله:\n\n${text}\n\n---\n\nتعليمات الإخراج - التزم بها حرفياً:\n1. ابدأ ردّك مباشرةً بعلامة { ولا تضف أي كلام قبل JSON.\n2. حقل pillars يجب أن يحتوي على 10 أركان بالضبط - لا 9 ولا 8 ولا أقل. أكمل الـ 10 كلها قبل أي شيء آخر.\n3. feedback لكل ركن: جملة واحدة فقط (لا أكثر).\n4. بعد إغلاق JSON أعِد GRAMMAR_START...GRAMMAR_END.` }] },
        ],
        generationConfig: { maxOutputTokens: 16384, temperature: 0.3 },
      }),
    }
  )
  if (!res.ok) {
    const errBody = await res.json().catch(() => ({}))
    const msg = errBody?.error?.message || res.status
    throw new Error("API: " + msg)
  }
  const data = await res.json()
  let raw: string = data.candidates?.[0]?.content?.parts?.[0]?.text || ""
  if (!raw) {
    const reason = data.candidates?.[0]?.finishReason || "unknown"
    throw new Error("الاستجابة فارغة - السبب: " + reason)
  }
  // Strip markdown fences and normalize newlines inside JSON
  raw = raw.replace(/```json\s*/gi, "").replace(/```\s*/g, "")
  const s = raw.indexOf("{")
  if (s === -1) throw new Error("لم يُعثر على JSON - الاستجابة: " + raw.slice(0, 200))
  // Walk forward counting braces to find the REAL closing } (not a later one in grammar/commentary)
  let depth = 0, inStr2 = false, esc2 = false, jsonEnd = -1
  for (let i = s; i < raw.length; i++) {
    const c = raw[i]
    if (esc2) { esc2 = false; continue }
    if (c === "\\" && inStr2) { esc2 = true; continue }
    if (c === '"') { inStr2 = !inStr2; continue }
    if (!inStr2) { if (c === "{") depth++; else if (c === "}") { depth--; if (depth === 0) { jsonEnd = i; break } } }
  }
  if (jsonEnd === -1) throw new Error("لم يُعثر على JSON - الاستجابة: " + raw.slice(0, 200))
  let jsonStr = raw.slice(s, jsonEnd + 1).replace(/[\r\n\t]+/g, " "), result: any
  try { result = JSON.parse(jsonStr) }
  catch (_) {
    let fixed = "", inStr = false, esc = false, prev = "open"
    for (let i = 0; i < jsonStr.length; i++) {
      const c = jsonStr[i]
      if (esc) { fixed += c; esc = false; continue }
      if (c === "\\") { fixed += c; esc = true; continue }
      if (inStr) {
        if (c === '"') { let j=i+1; while(j<jsonStr.length&&" \t\r\n".includes(jsonStr[j]))j++; const nx=jsonStr[j]; if(":,}]\"".includes(nx)||j>=jsonStr.length){inStr=false;prev="val";fixed+=c;}else fixed+='\\"' } else fixed += c
        continue
      }
      if (" \t\r\n".includes(c)) { fixed += c; continue }
      if (c==='"'){if(prev==="val")fixed+=",";inStr=true;fixed+=c;continue}
      if (c==="{"){if(prev==="val")fixed+=",";fixed+=c;prev="open";continue}
      if (c==="["){if(prev==="val")fixed+=",";fixed+=c;prev="open";continue}
      if (c==="}"){fixed+=c;prev="val";continue}
      if (c==="]"){fixed+=c;prev="val";continue}
      if (c===":"){fixed+=c;prev="colon";continue}
      if (c===","){fixed+=c;prev="comma";continue}
      fixed += c
    }
    fixed = fixed.replace(/,(\s*[}\]])/g,"$1")
    result = JSON.parse(fixed)
  }
  const gb = raw.match(/GRAMMAR_START([\s\S]*?)GRAMMAR_END/)
  result.grammar = []
  if (gb) {
    gb[1].trim().split("\n").forEach((line: string) => {
      line = line.trim(); if (!line) return
      const parts = line.split("|").map((p: string) => p.trim())
      const get = (p: string) => { const x = parts.find((q: string) => q.startsWith(p)); return x ? x.slice(p.length).trim() : "" }
      const w = get("خطأ:"), c = get("صحيح:")
      if (w && c) result.grammar.push({ wrong: w, correct: c, type: get("نوع:"), rule: get("قاعدة:"), sentence: get("جملة:") })
    })
  }
  const aiWrongs = new Set(result.grammar.map((g: any) => g.wrong))
  arabicGrammarCheck(text).forEach(e => { if (!aiWrongs.has(e.wrong)) result.grammar.push(e) })
  return result
}

// ─── Sparkline ─────────────────────────────────────────
function Sparkline({ data, color, width=80, height=36, showLabels=false, showArrow=false }: { data:number[], color:string, width?:number, height?:number, showLabels?:boolean, showArrow?:boolean }) {
  const labelW = showLabels ? 40 : 0
  const arrowH = showArrow ? 18 : 0
  const gh = height - arrowH
  const gw = width - labelW
  const pts = data.map((v, i) => {
    const x = labelW + gw - (i / (data.length - 1)) * gw
    const y = gh - (v / 10) * gh
    return `${x.toFixed(1)},${y.toFixed(1)}`
  }).join(" ")
  const fillPts = `${labelW + gw},${gh} ` + pts + ` ${labelW},${gh}`
  const arrowY = gh + 12
  return (
    <svg width={width} height={height} viewBox={`0 0 ${width} ${height}`} style={{display:"block"}}>
      {showLabels && <>
        <text x={labelW - 4} y={12} textAnchor="end" style={{fontSize:9,fontWeight:700,fill:"#12B76A",fontFamily:"'IBM Plex Sans Arabic',sans-serif"}}>السعادة</text>
        <text x={labelW - 4} y={gh - 3} textAnchor="end" style={{fontSize:9,fontWeight:700,fill:"#E82222",fontFamily:"'IBM Plex Sans Arabic',sans-serif"}}>التعاسة</text>
        <line x1={labelW} y1={0} x2={labelW} y2={gh} stroke="#E0E0E0" strokeWidth="0.5"/>
      </>}
      <polygon points={fillPts} fill={color + "20"}/>
      <polyline points={pts} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>
      {showArrow && <>
        <line x1={labelW + gw - 2} y1={arrowY} x2={labelW + 14} y2={arrowY} stroke="#AAAAAA" strokeWidth="1.2" strokeLinecap="round"/>
        <polyline points={`${labelW + 22},${arrowY - 3.5} ${labelW + 14},${arrowY} ${labelW + 22},${arrowY + 3.5}`} fill="none" stroke="#AAAAAA" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round"/>
        <text x={labelW + gw - 4} y={arrowY + 1} textAnchor="end" style={{fontSize:8,fontWeight:600,fill:"#AAAAAA",fontFamily:"'IBM Plex Sans Arabic',sans-serif"}} dominantBaseline="middle">البداية</text>
        <text x={labelW + 4} y={arrowY + 1} textAnchor="start" style={{fontSize:8,fontWeight:600,fill:"#AAAAAA",fontFamily:"'IBM Plex Sans Arabic',sans-serif"}} dominantBaseline="middle">النهاية</text>
      </>}
    </svg>
  )
}

