// ─── Canvas drawing helpers ────────────────────────────
function rrect(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) {
  ctx.beginPath()
  ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y); ctx.quadraticCurveTo(x+w,y,x+w,y+r)
  ctx.lineTo(x+w,y+h-r); ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h)
  ctx.lineTo(x+r,y+h); ctx.quadraticCurveTo(x,y+h,x,y+h-r)
  ctx.lineTo(x,y+r); ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath()
}
function wrapText(ctx: CanvasRenderingContext2D, text: string, cx: number, y: number, maxW: number, lh: number, maxL = 99): number {
  const words = text.split(" "); let line = "", row = 0
  for (const word of words) {
    const t = line ? line + " " + word : word
    if (ctx.measureText(t).width > maxW && line) {
      ctx.fillText(line, cx, y + row * lh); line = word; row++
      if (row >= maxL) { ctx.fillText(line + "...", cx, y + row * lh); return row + 1 }
    } else line = t
  }
  if (line) ctx.fillText(line, cx, y + row * lh)
  return row + 1
}

